class Solution {
    public int maxLengthBetweenEqualCharacters(String s) {
        int[] firstOccurrence = new int[26];
        int maxLength = -1;
        for (int i = 0; i < s.length(); i++) {
            int charIndex = s.charAt(i) - 'a';
            if (firstOccurrence[charIndex] == 0 && charIndex != 0) {
                firstOccurrence[charIndex] = i + 1;
            } else if (firstOccurrence[charIndex] != 0) {
                maxLength = Math.max(maxLength, i - firstOccurrence[charIndex]);
            } else {
                firstOccurrence[charIndex] = i + 1;
            }
        }
        return maxLength;
    }
}
